def solve(log_file_path, elasticsearch_url):
    import json
    from elasticsearch import Elasticsearch, exceptions

    # Validate inputs
    if not isinstance(log_file_path, str) or not isinstance(elasticsearch_url, str):
        raise ValueError("Invalid input types. Both arguments must be strings.")

    # Initialize Elasticsearch client
    es = Elasticsearch(elasticsearch_url)

    # Read data from log file
    try:
        with open(log_file_path, 'r') as log_file:
            for line in log_file:
                if line.strip():  # Check for non-empty lines
                    try:
                        document = json.loads(line)
                        es.index(index='logs', body=document)
                    except json.JSONDecodeError:
                        print(f"Skipping invalid JSON line: {line}")
                    except exceptions.ElasticsearchException as e:
                        print(f"Failed to index document: {e}")
    except FileNotFoundError:
        raise FileNotFoundError(f"Log file not found: {log_file_path}")
    except Exception as e:
        raise RuntimeError(f"An error occurred: {e}")

    return None
